package ru.memearena.user.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="user_profile")
public class UserProfile { @Id private UUID id; @Column(nullable=false,unique=true,length=30) private String nickname; @Column(name="votes_count",nullable=false) private long votesCount; @Column(name="submitted_memes_count",nullable=false) private long submittedMemesCount; @Column(name="created_at",nullable=false) private Instant createdAt; @Column(name="updated_at",nullable=false) private Instant updatedAt; protected UserProfile(){} public UserProfile(UUID id,String nickname,Instant now){this.id=id;this.nickname=nickname;this.createdAt=now;this.updatedAt=now;} public UUID getId(){return id;} public String getNickname(){return nickname;} public long getVotesCount(){return votesCount;} public long getSubmittedMemesCount(){return submittedMemesCount;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;} public UserStatus status(){return UserStatus.fromVotes(votesCount);} public void incrementVotes(Instant now){votesCount++;updatedAt=now;} public void incrementSubmittedMemes(Instant now){submittedMemesCount++;updatedAt=now;} }
